#include <stdio.h>

int main() {
    char operator;
    double num1, num2;

    printf("Enter operator (+, -, *, /): ");
    scanf("%c", &operator);

    printf("Enter two operands: ");
    scanf("%lf %lf", &num1, &num2);

    switch(operator) {
        case '+':
            printf("%.2lf + %.2lf = %.2lf\n", num1, num2, num1 + num2);
            break;
        case '-':
            printf("%.2lf - %.2lf = %.2lf\n", num1, num2, num1 - num2);
            break;
        case '*':
            printf("%.2lf * %.2lf = %.2lf\n", num1, num2, num1 * num2);
            break;
        case '/':
            if(num2 != 0)
                printf("%.2lf / %.2lf = %.2lf\n", num1, num2, num1 / num2);
            else
                printf("Error: Division by zero!\n");
            break;
        default:
            printf("Error: Invalid operator!\n");
    }

    return 0;
}

#include <stdio.h>

int main() {
    char day;

    printf("Enter first letter of day (M/T/W/F/S): ");
    scanf(" %c", &day);

    switch(day) {
        case 'M':
            printf("Monday\n");
            break;
        case 'T':
            printf("Enter second letter (u/e): ");
            scanf(" %c", &day);
            switch(day) {
                case 'u': printf("Tuesday\n"); break;
                case 'e': printf("Thursday\n"); break;
                default: printf("Invalid\n");
            }
            break;
        case 'W':
            printf("Wednesday\n");
            break;
        case 'F':
            printf("Friday\n");
            break;
        case 'S':
            printf("Enter second letter (a/u): ");
            scanf(" %c", &day);
            switch(day) {
                case 'a': printf("Saturday\n"); break;
                case 'u': printf("Sunday\n"); break;
                default: printf("Invalid\n");
            }
            break;
        default:
            printf("Invalid input\n");
    }

    return 0;
}

#include <stdio.h>

enum Grade { A = 90, B = 80, C = 70, D = 60 };

int main() {
    int score;

    printf("Enter your score (0-100): ");
    scanf("%d", &score);

    switch(score / 10) {
        case 10:
        case 9:
            printf("Grade: A (Excellent)\n");
            break;
        case 8:
            printf("Grade: B (Good)\n");
            break;
        case 7:
            printf("Grade: C (Average)\n");
            break;
        case 6:
            printf("Grade: D (Pass)\n");
            break;
        case 5:
        case 4:
        case 3:
        case 2:
        case 1:
        case 0:
            printf("Grade: F (Fail)\n");
            break;
        default:
            printf("Invalid score!\n");
    }

    return 0;
}
